(function() {
  const AVATAR = 'data:image/png;base64,';
  const BOT_NAME = 'BVM Bot';
  const PROXY_URL = (window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1')
    ? '/bot-proxy'
    : 'https://gatekeeper-bot-omega.vercel.app/api/chat';

  const SYSTEM_PROMPT = `You are BVM Bot, the AI CS coaching assistant for the BVM (Broad Vision Media) customer success and account management team. You have deep knowledge of the BVM CS playbook including:

- SPICED discovery framework (Situation, Pain, Impact, Critical Event, Decision)
- 90-day renewal protection motion
- Print-to-digital migration plays
- Decline management signals and response playbook
- SBR (Strategic Business Review) preparation
- Upsell and expansion motions
- Account health scoring and segmentation
- Bandwidth tracking for CS managers

You support three leaders: Ted (manager/VP), Kala (CS team with Genele and Karen), and Samantha (CS team with April and Alex). The book of business is $38M. You have context from the weekly Gatekeeper executive pack -- renewal report data, health scores, at-risk flags, and coaching summaries.

Be direct, concise, and playbook-driven. Lead with the action. No fluff. You are a hound dog on at-risk accounts.`;

  // -- Styles ----------------------------------------------
  const style = document.createElement('style');
  style.textContent = `
    #bvm-fab {
      position: fixed;
      bottom: 28px;
      right: 28px;
      width: 62px;
      height: 62px;
      border-radius: 50%;
      background: #1B2F5E;
      border: 3px solid #F5C842;
      cursor: pointer;
      overflow: hidden;
      z-index: 99998;
      box-shadow: 0 4px 16px rgba(0,0,0,0.25);
      transition: transform 0.15s;
    }
    #bvm-fab:hover { transform: scale(1.07); }
    #bvm-fab img {
      width: 130%;
      height: 130%;
      object-fit: cover;
      object-position: 20% 10%;
      margin-left: -15%;
      margin-top: -8%;
      pointer-events: none;
    }
    #bvm-panel {
      position: fixed;
      bottom: 104px;
      right: 28px;
      width: 340px;
      background: #fff;
      border-radius: 16px;
      border: 1px solid #E2E0D8;
      box-shadow: 0 8px 32px rgba(0,0,0,0.18);
      z-index: 99999;
      display: none;
      flex-direction: column;
      overflow: hidden;
      font-family: 'DM Sans', -apple-system, sans-serif;
    }
    #bvm-panel.open { display: flex; }
    #bvm-header {
      background: #1B2F5E;
      padding: 12px 14px;
      display: flex;
      align-items: center;
      gap: 10px;
    }
    #bvm-header-avatar {
      width: 36px; height: 36px;
      border-radius: 50%;
      background: #2A4278;
      overflow: hidden;
      flex-shrink: 0;
    }
    #bvm-header-avatar img {
      width: 130%; height: 130%;
      object-fit: cover;
      object-position: 20% 10%;
      margin-left: -15%; margin-top: -8%;
    }
    #bvm-header-name { font-size: 13px; font-weight: 600; color: #F5C842; }
    #bvm-header-status { font-size: 11px; color: #7A90B8; display: flex; align-items: center; gap: 4px; margin-top: 1px; }
    #bvm-status-dot { width: 6px; height: 6px; border-radius: 50%; background: #22C55E; }
    #bvm-close {
      margin-left: auto;
      background: none; border: none;
      color: #7A90B8; font-size: 18px;
      cursor: pointer; line-height: 1;
      padding: 0 2px;
    }
    #bvm-close:hover { color: #F5C842; }
    #bvm-messages {
      flex: 1;
      padding: 12px;
      display: flex;
      flex-direction: column;
      gap: 8px;
      height: 320px;
      overflow-y: auto;
      background: #F8F7F4;
    }
    .bvm-msg {
      max-width: 85%;
      padding: 8px 11px;
      border-radius: 12px;
      font-size: 12px;
      line-height: 1.55;
    }
    .bvm-bot {
      background: #fff;
      border: 0.5px solid #E2E0D8;
      color: #1A1A1A;
      align-self: flex-start;
      border-bottom-left-radius: 3px;
    }
    .bvm-user {
      background: #1B2F5E;
      color: #fff;
      align-self: flex-end;
      border-bottom-right-radius: 3px;
    }
    .bvm-thinking {
      background: #fff;
      border: 0.5px solid #E2E0D8;
      color: #8A8880;
      align-self: flex-start;
      border-bottom-left-radius: 3px;
      font-style: italic;
    }
    #bvm-input-row {
      display: flex;
      align-items: center;
      gap: 8px;
      padding: 10px 12px;
      border-top: 1px solid #E2E0D8;
      background: #fff;
    }
    #bvm-input {
      flex: 1;
      border: 1px solid #E2E0D8;
      border-radius: 20px;
      padding: 7px 12px;
      font-size: 12px;
      font-family: inherit;
      outline: none;
      background: #F8F7F4;
      color: #1A1A1A;
    }
    #bvm-input:focus { border-color: #1B2F5E; }
    #bvm-send {
      width: 30px; height: 30px;
      border-radius: 50%;
      background: #F5C842;
      border: none;
      cursor: pointer;
      display: flex; align-items: center; justify-content: center;
      flex-shrink: 0;
    }
    #bvm-send:hover { background: #e6b800; }
    #bvm-send svg { width: 13px; height: 13px; }
  `;
  document.head.appendChild(style);

  // -- FAB Button -------------------------------------------
  const fab = document.createElement('div');
  fab.id = 'bvm-fab';
  fab.innerHTML = `<img src="${AVATAR}" alt="BVM Bot">`;
  document.body.appendChild(fab);

  // -- Chat Panel -------------------------------------------
  const panel = document.createElement('div');
  panel.id = 'bvm-panel';
  panel.innerHTML = `
    <div id="bvm-header">
      <div id="bvm-header-avatar"><img src="${AVATAR}" alt="BVM Bot"></div>
      <div>
        <div id="bvm-header-name">${BOT_NAME}</div>
        <div id="bvm-header-status"><div id="bvm-status-dot"></div><span>Online . BVM CS Playbook</span></div>
      </div>
      <button id="bvm-close">&#x2715;</button>
    </div>
    <div id="bvm-messages"></div>
    <div id="bvm-input-row">
      <input id="bvm-input" type="text" placeholder="Ask BVM Bot anything..." />
      <button id="bvm-send">
        <svg viewBox="0 0 24 24" fill="none" stroke="#1B2F5E" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round">
          <line x1="22" y1="2" x2="11" y2="13"/>
          <polygon points="22 2 15 22 11 13 2 9 22 2"/>
        </svg>
      </button>
    </div>
  `;
  document.body.appendChild(panel);

  // -- State -------------------------------------------------
  let history = [];
  let isOpen = false;

  function togglePanel() {
    isOpen = !isOpen;
    panel.classList.toggle('open', isOpen);
    if (isOpen && history.length === 0) {
      addMessage("Hey -- I've got the renewal report loaded. What do you need?", 'bot');
    }
  }

  fab.addEventListener('click', togglePanel);
  panel.querySelector('#bvm-close').addEventListener('click', togglePanel);

  // -- Messaging ---------------------------------------------
  function addMessage(text, role) {
    const msgs = document.getElementById('bvm-messages');
    const div = document.createElement('div');
    div.className = 'bvm-msg bvm-' + role;
    div.textContent = text;
    msgs.appendChild(div);
    msgs.scrollTop = msgs.scrollHeight;
    return div;
  }

  async function sendMessage() {
    const input = document.getElementById('bvm-input');
    const text = input.value.trim();
    if (!text) return;

    addMessage(text, 'user');
    history.push({ role: 'user', content: text });
    input.value = '';

    const thinking = addMessage('thinking...', 'thinking');

    try {
      const res = await fetch(PROXY_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          model: 'claude-haiku-4-5-20251001',
          system: SYSTEM_PROMPT,
          messages: history,
          max_tokens: 300
        })
      });
      const data = await res.json();
      const reply = data.content?.[0]?.text || 'Something went wrong -- check the proxy.';
      thinking.remove();
      addMessage(reply, 'bot');
      history.push({ role: 'assistant', content: reply });
    } catch (err) {
      thinking.remove();
      addMessage('Connection error -- is the Vercel proxy up?', 'bot');
    }
  }

  document.getElementById('bvm-send').addEventListener('click', sendMessage);
  document.getElementById('bvm-input').addEventListener('keydown', e => {
    if (e.key === 'Enter') sendMessage();
  });

})();